  1→import './signup.css'
  2→import React, { useEffect, useState } from "react";
  3→import { useNavigate } from "react-router-dom";
  4→import supabase from '../../utils/supabaseClient';
  5→import Turnstile from 'react-turnstile'
  6→import { useAuth } from '../../Context/useAuth';
  7→import BASE_URL from '../../utils/apiBaseUrl';
  8→import apiRequest from '../../utils/apiRequest';
  9→
 10→const SITE_KEY = import.meta.env.VITE_SITE_KEY;
 11→
 12→const SignUp = () => {
 13→    const { session } = useAuth();
 14→
 15→    const [password, setPassword] = useState('');
 16→    const [email, setEmail] = useState('');
 17→    const [showPass, setShowPass] = useState(false)
 18→    const [errorMessage, setErrorMessage] = useState(null);
 19→    const [isLoadingSignUp, setIsLoadingSignUp] = useState(false)
 20→    const [successMessage, setSuccessMessage] = useState('');
 21→    const navigate = useNavigate();
 22→
 23→    const [captchaToken, setCaptchaToken] = useState(null);
 24→
 25→    const handleShowPass = (e) =>{
 26→        e.preventDefault();
 27→        setShowPass((prev) => !prev)
 28→    }
 29→
 30→    const handleSignUp = async(e) =>{
 31→        e.preventDefault();
 32→        setErrorMessage(null);
 33→        setSuccessMessage('');
 34→        setIsLoadingSignUp(true)
 35→        const validateEmail = (email) =>{
 36→            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 37→            return emailRegex.test(email)
 38→        }
 39→        if(!validateEmail(email)){
 40→            setIsLoadingSignUp(false)
 41→           return setErrorMessage('Email is not valid')
 42→        }
 43→        if (!captchaToken) {
 44→            setIsLoadingSignUp(false)
 45→            return setErrorMessage("Please complete the CAPTCHA first.");
 46→        }
 47→
 48→        try {
 49→            const res = await apiRequest(`${BASE_URL}/verify-turnstile`, {
 50→                method: 'POST',
 51→                headers: { 'Content-Type': 'application/json' },
 52→                body: JSON.stringify({ token: captchaToken }),
 53→            })
 54→
 55→            const result = await res.json();
 56→
 57→            if (!result.success) {
 58→                return setErrorMessage("CAPTCHA verification failed. Try again.");
 59→            }
 60→
 61→            const { error: error } = await supabase.auth.signUp({
 62→                email: email,
 63→                password: password
 64→            })
 65→            if(error.message){
 66→                return setErrorMessage(error.message)
 67→            }
 68→            setSuccessMessage('Account created. Check your email to confirm.');
 69→            setTimeout(() => navigate('/home'), 600);
 70→        } catch (error) {
 71→            console.error('Error during sign-up:', error.message);
 72→            setErrorMessage(error.message);
 73→        } finally {
 74→            setEmail('');
 75→            setPassword('');
 76→            setIsLoadingSignUp(false)
 77→        }
 78→
 79→    }
 80→    const handleNavigate = (e) => {
 81→        e.preventDefault();
 82→        return navigate('/login');
 83→    }
 84→
 85→    useEffect(() =>{
 86→        if(session){
 87→            return navigate('/home')
 88→        }
 89→    }, [session, navigate])
 90→
 91→    const isSubmitDisabled = !email || !password || !captchaToken || isLoadingSignUp;
 92→
 93→    return(
 94→        <div className='auth-shell signup-shell'>
 95→            <section className='auth-panel'>
 96→                <div className='brand'>Iskrib</div>
 97→                <h1 className='panel-title'>Create your quiet writing space.</h1>
 98→                <p className='panel-copy'>
 99→                    Keep your poems, journals, and reflections beautifully organized.
100→                </p>
101→                <div className='panel-details'>
102→                    Private drafts · Elegant publishing · Calm community
103→                </div>
104→            </section>
105→
106→            <section className='auth-form-panel'>
107→                <div className='auth-form-card'>
108→                    <div>
109→                        <div className='form-title'>Create an account</div>
110→                        <p className='form-subtitle'>Start writing in minutes.</p>
111→                    </div>
112→
113→                    <form className='auth-form' onSubmit={handleSignUp} aria-busy={isLoadingSignUp ? 'true' : 'false'}>
114→                        <div className='form-field'>
115→                            <label htmlFor='signup-email'>Email</label>
116→                            <div className='input-with-action'>
117→                                <input
118→                                    id='signup-email'
119→                                    maxLength={50}
120→                                    value={email}
121→                                    onChange={(e) => setEmail(e.target.value)}
122→                                    className='auth-input'
123→                                    type='email'
124→                                    placeholder='you@iskrib.com'
125→                                    autoComplete='email'
126→                                    required
127→                                />
128→                                {email && (
129→                                    <div
130→                                        style={email.length >= 50 ? { color: 'rgb(184, 76, 76)' } : {}}
131→                                        className='length-counter'
132→                                    >
133→                                        {`${email.length}/50`}
134→                                    </div>
135→                                )}
136→                            </div>
137→                        </div>
138→
139→                        <div className='form-field'>
140→                            <label htmlFor='signup-password'>Password</label>
141→                            <div className='input-with-action'>
142→                                <input
143→                                    id='signup-password'
144→                                    value={password}
145→                                    onChange={(e) => setPassword(e.target.value)}
146→                                    className='auth-input'
147→                                    type={showPass ? 'text' : "password"}
148→                                    placeholder='Create a password'
149→                                    autoComplete='new-password'
150→                                    required
151→                                />
152→                                <button className='show-toggle' type='button' onClick={handleShowPass}>
153→                                    {showPass ? 'Hide' : 'Show'}
154→                                </button>
155→                            </div>
156→                        </div>
157→
158→                        <div className='captcha-container'>
159→                            <Turnstile
160→                                sitekey={SITE_KEY}
161→                                onVerify={(token) => setCaptchaToken(token)}
162→                                onExpire={() => setCaptchaToken(null)}
163→                                onError={() => setCaptchaToken(null)}
164→                                theme='light'
165→                            />
166→                        </div>
167→
168→                        <button className='primary-button' type='submit' disabled={isSubmitDisabled}>
169→                            <span className='button-label'>Create account</span>
170→                            {isLoadingSignUp && <span className='button-spinner' aria-hidden='true' />}
171→                        </button>
172→
173→                        <button
174→                            className='secondary-button'
175→                            type='button'
176→                            onClick={() => navigate('/home')}
177→                            disabled={isLoadingSignUp}
178→                        >
179→                            Explore Iskrib
180→                        </button>
181→                    </form>
182→
183→                    <div className='auth-footer'>
184→                        Have an account?
185→                        <button className='link-button' type='button' onClick={handleNavigate}>
186→                            Log in
187→                        </button>
188→                    </div>
189→
190→                    {errorMessage && (
191→                        <div className='form-message error' role='alert'>
192→                            {errorMessage}
193→                        </div>
194→                    )}
195→
196→                    {successMessage && (
197→                        <div className='form-message success' role='status'>
198→                            {successMessage}
199→                        </div>
200→                    )}
201→                </div>
202→            </section>
203→        </div>
204→    )
205→}
206→export default SignUp;
207→
